// ShareActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Patterns
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream

class ShareActivity : AppCompatActivity() {

    companion object {
        private const val MAX_FILE_SIZE = 10 * 1024 * 1024 // 10MB
        private val ALLOWED_MIME_TYPES = setOf(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp",
            "text/plain"
        )
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        if (!validateCaller()) {
            Toast.makeText(this, "Unauthorized access", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        when {
            intent?.action == Intent.ACTION_SEND -> {
                handleSendIntent(intent)
            }
            intent?.action == Intent.ACTION_SEND_MULTIPLE -> {
                handleSendMultipleIntent(intent)
            }
            else -> {
                Toast.makeText(this, "Invalid intent action", Toast.LENGTH_SHORT).show()
                finish()
            }
        }
    }

    private fun validateCaller(): Boolean {
        val callingPackage = callingPackage
        if (callingPackage == null) {
            val referrer = referrer
            if (referrer == null) {
                return false
            }
        }
        return true
    }

    private fun handleSendIntent(intent: Intent) {
        val type = intent.type
        
        if (type == null || !validateMimeType(type)) {
            Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        when {
            type.startsWith("text/") -> {
                handleTextShare(intent)
            }
            type.startsWith("image/") -> {
                handleImageShare(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
                finish()
            }
        }
    }

    private fun handleSendMultipleIntent(intent: Intent) {
        val type = intent.type
        
        if (type == null || !validateMimeType(type)) {
            Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        if (type.startsWith("image/")) {
            handleMultipleImagesShare(intent)
        } else {
            Toast.makeText(this, "Multiple items only supported for images", Toast.LENGTH_SHORT).show()
            finish()
        }
    }

    private fun validateMimeType(mimeType: String): Boolean {
        return ALLOWED_MIME_TYPES.any { mimeType.startsWith(it.substringBefore("/*")) }
    }

    private fun handleTextShare(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        
        if (sharedText.isNullOrBlank()) {
            Toast.makeText(this, "No text content found", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        val sanitizedText = sanitizeText(sharedText)
        
        if (isValidUrl(sanitizedText)) {
            processUrl(sanitizedText)
        } else {
            processText(sanitizedText)
        }
    }

    private fun handleImageShare(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUri == null) {
            Toast.makeText(this, "No image found", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        if (!validateUri(imageUri)) {
            Toast.makeText(this, "Invalid or unsafe image URI", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        processImage(imageUri)
    }

    private fun handleMultipleImagesShare(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUris.isNullOrEmpty()) {
            Toast.makeText(this, "No images found", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        val validUris = imageUris.filter { validateUri(it) }
        
        if (validUris.isEmpty()) {
            Toast.makeText(this, "No valid images found", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        processMultipleImages(validUris)
    }

    private fun sanitizeText(text: String): String {
        return text.trim().take(10000)
    }

    private fun isValidUrl(text: String): Boolean {
        return Patterns.WEB_URL.matcher(text).matches() && 
               (text.startsWith("http://") || text.startsWith("https://"))
    }

    private fun validateUri(uri: Uri): Boolean {
        try {
            val scheme = uri.scheme
            if (scheme != "content" && scheme != "file") {
                return false
            }

            contentResolver.openInputStream(uri)?.use { inputStream ->
                val fileSize = inputStream.available()
                if (fileSize > MAX_FILE_SIZE) {
                    return false
                }
            } ?: return false

            val mimeType = contentResolver.getType(uri)
            if (mimeType == null || !validateMimeType(mimeType)) {
                return false
            }

            return true
        } catch (e: Exception) {
            return false
        }
    }

    private fun processUrl(url: String) {
        Toast.makeText(this, "Processing URL: $url", Toast.LENGTH_LONG).show()
        
        // Process the URL here
        // Example: Save to database, open in browser, download content, etc.
        
        finish()
    }

    private fun processText(text: String) {
        Toast.makeText(this, "Processing text: ${text.take(50)}...", Toast.LENGTH_LONG).show()
        
        // Process the text here
        // Example: Save to database, analyze content, etc.
        
        finish()
    }

    private fun processImage(imageUri: Uri) {
        try {
            contentResolver.openInputStream(imageUri)?.use { inputStream ->
                val fileName = "shared_image_${System.currentTimeMillis()}.jpg"
                val outputFile = File(filesDir, fileName)
                
                FileOutputStream(outputFile).use { outputStream ->
                    inputStream.copyTo(outputStream)
                }
                
                Toast.makeText(this, "Image saved: ${outputFile.absolutePath}", Toast.LENGTH_LONG).show()
                
                // Process the image here
                // Example: Upload to server, apply filters, etc.
            }
        } catch (e: Exception) {
            Toast.makeText(this, "Error processing image: ${e.message}", Toast.LENGTH_SHORT).show()
        } finally {
            finish()
        }
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        var successCount = 0
        
        imageUris.forEachIndexed { index, uri ->
            try {
                contentResolver.openInputStream(uri)?.use { inputStream ->
                    val fileName = "shared_image_${System.currentTimeMillis()}_$index.jpg"
                    val outputFile = File(filesDir, fileName)
                    
                    FileOutputStream(outputFile).use { outputStream ->
                        inputStream.copyTo(outputStream)
                    }
                    successCount++
                }
            } catch (e: Exception) {
                // Continue processing other images
            }
        }
        
        Toast.makeText(this, "Processed $successCount of ${imageUris.size} images", Toast.LENGTH_LONG).show()
        
        // Process the images here
        // Example: Create album, upload batch, etc.
        
        finish()
    }
}